using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 renamed the default discriminator from "Discriminator" to "$type".
        // Preserve the old name so existing documents and raw SQL queries
        // (e.g. SELECT * FROM c WHERE c.Discriminator = 'Blog') keep working.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer embeds the discriminator in the JSON id.
        // Existing documents use the "Blog|1" format; preserve it.
        modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

        // HasIndex now throws for Cosmos DB entities.
        // Cosmos indexing is managed via the container's indexing policy, not EF Core.
        // REMOVED: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}

