using Microsoft.EntityFrameworkCore;

class SyncJob
{
    // EF Core 9 Cosmos DB provider no longer supports synchronous I/O.
    // ToList() and SaveChanges() must become async equivalents.
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

